// Recibe { id, token } — id puede venir como número o 'r_<n>'.
const src = $input.first().json;
const body = src.body || src;
let rawId = body.id;
if (typeof rawId === 'string' && rawId.startsWith('r_')) rawId = rawId.slice(2);
const quoteId = Number(rawId);
const token = String(body.token || '').trim();
if (!Number.isFinite(quoteId) || quoteId <= 0) throw new Error('id inválido');
if (!token) throw new Error('token requerido');
return [{ json: { quoteId, token } }];

// Valida token y devuelve payload PÚBLICO (sin notas internas).
const input = $('Validate input').first().json;
const row = $input.first().json;
if (!row || !row.id) {
  return [{ json: { ok: false, reason: 'no encontrada' } }];
}
const payload = row.payload || {};
if (!payload.trackingToken) {
  return [{ json: { ok: false, reason: 'sin token (admin debe abrir la cotización primero)' } }];
}
if (payload.trackingToken !== input.token) {
  return [{ json: { ok: false, reason: 'token inválido' } }];
}
// Filtra historial: solo cambios de estado (no notas internas)
const publicHistory = (Array.isArray(payload.history) ? payload.history : [])
  .filter(h => h.fromStatus && h.toStatus)
  .map(h => ({ at: h.at, fromStatus: h.fromStatus, toStatus: h.toStatus }));
return [{ json: {
  ok: true,
  quote: {
    id: row.id,
    createdAt: row.created_at,
    status: row.status,
    systemType: row.system_type,
    kwp: row.kwp,
    numPanels: row.num_panels,
    dept: row.dept,
    address: row.address,
    totalCop: row.total_cop,
    annualSavCop: row.annual_sav_cop,
    roiYears: row.roi_years,
    coveragePct: row.coverage_pct,
    customer: { name: row.name, email: row.email },
    history: publicHistory,
    monthlyKwh: payload.monthlyKwh || null,
    operator: payload.operator || null,
    results: payload.results || null,
    budget: payload.budget || null,
    panel: payload.panel ? { brand: payload.panel.brand, model: payload.panel.model, wp: payload.panel.wp } : null,
  }
} }];
